"use strict";parserFactory.register("foxteller.com",()=>new FoxtellerParser);class FoxtellerParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".card li a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.querySelector("div.novel-title h2")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"figure.novel-featureimg")}async fetchChapter(e){let t=(await HttpClient.wrapFetch(e)).responseXML,r=await this.fetchContentForChapter(t),n=Parser.makeEmptyDocForContent(e),a=n.dom.createElement("h1");return a.textContent=t.querySelector("div.page-header h3").textContent,n.content.appendChild(a),n.content.appendChild(r.querySelector("article")),n.dom}async fetchContentForChapter(e){let t=e.head.innerText,r=t.match(/.*?novel_id'\s?:\s?'([\w\s]+)'/i)[1],n=t.match(/.*?chapter_id'\s?:\s?'([\w\s]+)'/i)[1],a={method:"POST",headers:{Accept:"application/json","Content-Type":"application/json"},credentials:"include",body:JSON.stringify({x1:r,x2:n})},o=(await HttpClient.fetchJson("https://www.foxteller.com/aux_dem",a)).json,l="<article>"+this.decodeFoxteller(o)+"</article>";return util.sanitize(l)}decodeFoxteller(e){var t=e.aux.replace(/%Ra&/g,"A").replace(/%Rc&/g,"B").replace(/%Rb&/g,"C").replace(/%Rd&/g,"D").replace(/%Rf&/g,"E").replace(/%Re&/g,"F");return decodeURIComponent(Array.prototype.map.call(atob(t),function(e){return"%"+("00"+e.charCodeAt(0).toString(16)).slice(-2)}).join(""))}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.novel-description")]}}